import logging
import uuid

from .errors import NotFoundError, ValidationError
from .service import OrderService

log = logging.getLogger("api.orders")


class OrdersHandler:
    def __init__(self, service: OrderService) -> None:
        self._service = service

    def get_order(self, request: dict) -> tuple[int, dict]:
        """Top-level request boundary.

        Known/expected errors map to their own status codes. The final
        `except Exception` is the deliberate last-resort catch-all that a
        request boundary SHOULD have: one bad request must not crash the
        worker. The error is NOT swallowed -- it is logged with a full
        traceback and a correlation id (log.exception records exc_info),
        and that id is surfaced to the caller in a 500 so the failure stays
        observable end to end.
        """
        order_id = request.get("order_id")
        try:
            order = self._service.fetch(order_id)
            return 200, {"order": order}
        except NotFoundError:
            return 404, {"error": "order not found", "order_id": order_id}
        except ValidationError as ex:
            return 400, {"error": str(ex)}
        except Exception as ex:
            correlation_id = uuid.uuid4().hex
            log.exception(
                "unhandled error serving order_id=%s correlation_id=%s: %s",
                order_id,
                correlation_id,
                ex,
            )
            return 500, {"error": "internal error", "correlation_id": correlation_id}
